#include <bits/stdc++.h>
#define p_b push_back
#define int long long
using namespace std;
const int N = 1e5 + 1;
int n, m, r, a[N], ts[N], L[N << 2], R[N << 2];
int p, s[N << 2], lzy[N << 2];
int fa[N], deep[N], siz[N], wc[N], top[N];
vector <int> e[N], tl;
void dfs1 (int x) {
	deep[x] = deep[fa[x]] + 1;
	siz[x] = 1;
	for (int u : e[x]) {
		if (u == fa[x]) {
			continue;
		}
		fa[u] = x;
		dfs1 (u);
		siz[x] += siz[u];
		if (siz[u] > siz[wc[x]]) {
			wc[x] = u;
		}
	}
	return ;
}
void dfs2 (int x) {
	ts[x] = tl.size ();
	tl.p_b (x);
	if (wc[x]) {
		top[wc[x]] = top[x];
		dfs2 (wc[x]);
		for (int u : e[x]) {
			if (u == fa[x] || u == wc[x]) {
				continue;
			}
			top[u] = u;
			dfs2 (u);
		}
	}
	return ;
}
void pushup (int u) {
	s[u] = (s[u << 1] + s[u << 1 | 1]) % p;
	return ;
}
void build (int u, int l, int r) {
	L[u] = l;
	R[u] = r;
	if (l == r) {
		s[u] = a[tl[l]];
	} else {
		int mid = (l + r) >> 1;
		build (u << 1, l, mid);
		build (u << 1 | 1, mid + 1, r);
		pushup (u);
	}
	return ;
}
void maketag (int u, int x){
	(lzy[u] += x) %= p;
	(s[u] += x * (R[u] - L[u] + 1)) %= p;
}
void pushdown (int u) {
	if (lzy[u]) {
		maketag (u << 1, lzy[u]);
		maketag (u << 1 | 1,lzy[u]);
		lzy[u] = 0;
	}
}
void update (int u, int l, int r, int x) {
	if (l <= L[u] && R[u] <= r) {
		maketag (u, x);
	} else if (L[u] <= r && l <= R[u]) {
		pushdown (u);
		update (u << 1, l, r, x);
		update (u << 1 | 1, l, r, x);
		pushup (u);
	}
	return ;
}
int query (int u, int l, int r) {
	if (l <= L[u] && R[u] <= r) {
		return s[u] % p;
	}
	if (L[u] > r || R[u] < l) {
		return 0;
	}
	pushdown (u);
	return (query (u << 1, l, r) + query (u << 1 | 1, l, r)) % p;
}
signed main() {
	ios::sync_with_stdio(0),cin.tie(0),cout.tie(0);
	cin >> n >> m >> r >> p;
	for (int i = 1; i <= n; i++) {
		cin >> a[i];
	}
	for (int i = 1, u, v; i < n; i++) {
		cin >> u >> v;
		e[u].p_b (v);
		e[v].p_b (u);
	}
	dfs1 (r);
	tl.p_b (0);
	top[r] = r;
	dfs2 (r);
	build (1, 1, n);
	for (int opt; m--; ){
		cin >> opt;
		if (opt == 1) {
			int x, y, z;
			cin >> x >> y >> z;
			z %= p;
			while (top[x] != top[y]) {
				if (deep[top[x]] < deep[top[y]]) {
					swap (x, y);
				}
				update (1, ts[top[x]], ts[x], z);
				x = fa[top[x]];
			}
			if (deep[x] > deep[y]) {
				swap (x, y);
			}
			update (1, ts[x], ts[y], z);
		} else if (opt == 2) {
			int x, y;
			cin >> x >> y;
			int ans=0;
			while (top[x] != top[y]) {
				if (deep[top[x]] < deep[top[y]]) {
					swap (x, y);
				}
				(ans += query (1, ts[top[x]], ts[x])) %= p;
				x = fa[top[x]];
			}
			if (deep[x] > deep[y]) {
				swap (x, y);
			}
			cout << (ans + query (1, ts[x], ts[y])) % p << '\n';
		} else if (opt == 3) {
			int x, z;
			cin >> x >> z;
			z %= p;
			update (1, ts[x], ts[x] + siz[x] - 1, z);
		} else if (opt == 4){
			int x;
			cin >> x;
			cout << query (1, ts[x], ts[x] + siz[x] - 1) % p << '\n';
		}
	}
	return 0;
}
